import axios from 'axios';
import qs from 'qs';

export class MStockClient {
  private baseUrl = 'https://api.mstock.trade/openapi/typea';
  public apiKey: string = '';
  public userId: string = '';
  public password: string = '';
  public accessToken: string = '';

  private get headers() {
    return {
      'Authorization': `token ${this.apiKey}:${this.accessToken}`,
      'Content-Type': 'application/x-www-form-urlencoded'
    };
  }

  async loginStep1(userId: string, pass: string) {
    this.userId = userId;
    this.password = pass;
    try {
      const res = await axios.post(`${this.baseUrl}/connect/login`, qs.stringify({
        userId: this.userId,
        password: this.password
      }), { headers: { 'Content-Type': 'application/x-www-form-urlencoded' } });
      return res.data;
    } catch (e: any) {
      return { status: 'error', message: e.message };
    }
  }

  async verifyTOTP(apiKey: string, totp: string) {
    this.apiKey = apiKey;
    try {
      const res = await axios.post(`${this.baseUrl}/session/verifytotp`, qs.stringify({
        userId: this.userId,
        totp: totp
      }), { headers: { 'Content-Type': 'application/x-www-form-urlencoded' } });
      
      if (res.data.status === 'success') {
        this.accessToken = res.data.data.accessToken;
      }
      return res.data;
    } catch (e: any) {
      return { status: 'error', message: e.message };
    }
  }

  async placeOrder(symbol: string, qty: number, side: string, price: number, orderType: string, exchange: string | null = null, trigger_price: number = 0) {
    if (!exchange) exchange = this.detectExchange(symbol);
    
    const payload = {
      tradingsymbol: symbol,
      exchange: exchange,
      transaction_type: side,
      quantity: qty,
      price: price,
      trigger_price: trigger_price,
      product: 'MIS',
      order_type: orderType,
      validity: 'DAY'
    };

    try {
      const res = await axios.post(`${this.baseUrl}/orders/regular`, qs.stringify(payload), { headers: this.headers });
      return res.data;
    } catch (e: any) {
      return { status: 'error', message: e.message };
    }
  }

  async cancelOrder(orderId: string) {
    try {
      const res = await axios.delete(`${this.baseUrl}/orders/regular/${orderId}`, { headers: this.headers });
      return res.data;
    } catch (e: any) {
      return { status: 'error', message: e.message };
    }
  }

  async getPositions() {
    try {
      const res = await axios.get(`${this.baseUrl}/portfolio/positions`, { headers: this.headers });
      return res.data;
    } catch (e: any) {
      return { status: 'error', message: e.message };
    }
  }

  async getFunds() {
    try {
      const res = await axios.get(`${this.baseUrl}/funds/limit`, { headers: this.headers });
      return res.data?.data?.available_margin || 0;
    } catch (e) {
      return 0;
    }
  }

  async getOrderBook() {
    try {
      const res = await axios.get(`${this.baseUrl}/orders`, { headers: this.headers });
      return res.data?.data || [];
    } catch (e) {
      return [];
    }
  }

  private detectExchange(symbol: string): string {
    const nfoIndices = ['NIFTY', 'BANKNIFTY', 'FINNIFTY', 'MIDCPNIFTY', 'NIFTYNXT50'];
    const bfoIndices = ['SENSEX', 'BANKEX'];
    
    for (const idx of nfoIndices) if (symbol.startsWith(idx)) return 'NFO';
    for (const idx of bfoIndices) if (symbol.startsWith(idx)) return 'BFO';
    return 'NSE';
  }
}
