import axios from 'axios';
import { format, subDays, startOfDay, getUnixTime } from 'date-fns';

export class DhanClient {
  private clientId: string;
  private accessToken: string;
  private baseUrl = 'https://api.dhan.co';

  constructor(clientId: string, accessToken: string) {
    this.clientId = clientId;
    this.accessToken = accessToken;
  }

  private get headers() {
    return {
      'access-token': this.accessToken,
      'client-id': this.clientId,
      'Content-Type': 'application/json'
    };
  }

  private unwrap(response: any) {
    if (!response || response.status !== 'success') return null;
    let data = response.data;
    if (data && data.status === 'success' && data.data) return data.data;
    if (data && data.data && Object.keys(data).length === 1) return data.data;
    return data;
  }

  async getQuoteBatch(query: Record<string, number[]>) {
    try {
      const res = await axios.post(`${this.baseUrl}/marketfeed/quote`, query, { headers: this.headers });
      return this.unwrap(res.data);
    } catch (e) {
      console.error('Dhan Quote Error', e);
      return null;
    }
  }

  async getHistory(securityId: string, segment: string, instType: string, timeframe: number | string) {
    try {
      const toDate = new Date();
      const fromDate = subDays(toDate, 7);
      const payload = {
        symbol: securityId,
        exchangeSegment: segment,
        instrumentType: instType,
        expiryCode: 0,
        fromDate: format(fromDate, 'yyyy-MM-dd HH:mm:ss'),
        toDate: format(toDate, 'yyyy-MM-dd HH:mm:ss')
      };
      const res = await axios.post(`${this.baseUrl}/charts/intraday`, payload, { headers: this.headers });
      const data = this.unwrap(res.data);
      if (!data || !data.timestamp) return [];

      const history = data.timestamp.map((t: number, i: number) => ({
        time: t,
        open: data.open[i],
        high: data.high[i],
        low: data.low[i],
        close: data.close[i],
        volume: data.volume[i]
      }));

      // Basic aggregation if timeframe > 1
      if (typeof timeframe === 'number' && timeframe > 1) {
        return this.aggregateOHLC(history, timeframe);
      }
      return history;
    } catch (e) {
      console.error('Dhan History Error', e);
      return [];
    }
  }

  private aggregateOHLC(bars: any[], tf: number) {
    if (bars.length === 0) return [];
    const windowSec = tf * 60;
    const aggregated: any[] = [];
    let currentBar: any = null;

    for (const bar of bars) {
      const windowStart = Math.floor(bar.time / windowSec) * windowSec;
      if (!currentBar || windowStart !== currentBar.time) {
        if (currentBar) aggregated.append(currentBar);
        currentBar = { ...bar, time: windowStart };
      } else {
        currentBar.high = Math.max(currentBar.high, bar.high);
        currentBar.low = Math.min(currentBar.low, bar.low);
        currentBar.close = bar.close;
        currentBar.volume += bar.volume;
      }
    }
    if (currentBar) aggregated.push(currentBar);
    return aggregated;
  }

  async getOptionChain(securityId: number, segment: string, expiry: string) {
    try {
      const payload = {
        underlyingId: securityId,
        underlyingSegment: segment,
        expiry: expiry
      };
      const res = await axios.post(`${this.baseUrl}/optionchain`, payload, { headers: this.headers });
      const unwrapped = this.unwrap(res.data);
      if (!unwrapped) return [];
      
      const oc = unwrapped.oc || unwrapped;
      const rows: any[] = [];
      
      const strikeKeys = Object.keys(oc);
      for (const strike of strikeKeys) {
        const item = oc[strike];
        const row: any = { Strike: parseFloat(strike) };
        
        if (item.ce) {
          row.Call_OI = item.ce.oi || 0;
          row.Call_LTP = item.ce.last_price || 0;
          row.Call_IV = item.ce.implied_volatility || 0;
          row.Call_Delta = item.ce.greeks?.delta || 0;
          row.Call_SecurityId = item.ce.security_id;
          row.Call_Symbol = item.ce.trading_symbol;
        }
        if (item.pe) {
          row.Put_OI = item.pe.oi || 0;
          row.Put_LTP = item.pe.last_price || 0;
          row.Put_IV = item.pe.implied_volatility || 0;
          row.Put_Delta = item.pe.greeks?.delta || 0;
          row.Put_SecurityId = item.pe.security_id;
          row.Put_Symbol = item.pe.trading_symbol;
        }
        rows.push(row);
      }
      return rows.sort((a,b) => a.Strike - b.Strike);
    } catch (e) {
      console.error('Dhan Option Chain Error', e);
      return [];
    }
  }

  async getExpiryList(securityId: number, segment: string) {
    try {
      const res = await axios.post(`${this.baseUrl}/optionchain/expiry`, { underlyingId: securityId, underlyingSegment: segment }, { headers: this.headers });
      return this.unwrap(res.data) || [];
    } catch (e) {
      return [];
    }
  }
}
